record.field:
{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Partner name or company name to search for (partial match supported). Use this as the primary search term."},
    "email": {"type": "string", "description": "Email address to filter by (optional). Useful when searching by known email."},
    "phone": {"type": "string", "description": "Phone number to filter by (optional). Partial match supported."},
    "limit": {"type": "integer", "description": "Maximum number of results to return. Default is 10. Use higher values (20-50) when user asks for 'all' or 'list all'."}
  },
  "required": ["name"]
}

{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Full name or company name of the partner (REQUIRED). This is the primary identifier."},
    "email": {"type": "string", "description": "Email address for the partner. Highly recommended for customer communications."},
    "phone": {"type": "string", "description": "Contact phone number with country code if possible."},
    "website": {"type": "string", "description": "Company website URL (optional). Include http:// or https://."},
    "country_id": {"type": "integer", "description": "Country ID for the partner. Find the country first using partner_search if needed."}
  },
  "required": ["name"]
}

{
  "type": "object",
  "properties": {
    "partner_name": {"type": "string", "description": "Customer name to filter orders by. Use exact customer name or company name as shown in partner records."},
    "state": {"type": "string", "enum": ["draft", "sent", "sale", "done", "cancel"], "description": "Order status/filter. Options: 'draft' (not yet sent), 'sent' (quotation sent), 'sale' (confirmed order), 'done' (completed), 'cancel' (cancelled). Leave empty to see all states."},
    "limit": {"type": "integer", "description": "Maximum number of results. Default is 10. Use 20-50 when user asks for 'all' or multiple orders."}
  }
}

{
  "type": "object",
  "properties": {
    "partner_id": {"type": "integer", "description": "Customer/Partner ID (REQUIRED). First find the customer using partner_search to get their ID."},
    "order_line": {
      "type": "array",
      "description": "Order line items (REQUIRED). At least one product is needed.",
      "items": {
        "type": "object",
        "properties": {
          "product_id": {"type": "integer", "description": "Product ID (REQUIRED). Find product using product_search first."},
          "product_uom_qty": {"type": "number", "description": "Quantity to order (REQUIRED). Default is 1."},
          "price_unit": {"type": "number", "description": "Unit price (optional). Leave empty to use product's list price."}
        }
      }
    }
  },
  "required": ["partner_id", "order_line"]
}

{
  "type": "object",
  "properties": {
    "id": {"type": "integer", "description": "Sales order ID to confirm (REQUIRED). First find the order using sale_order_search. Only works on orders in 'draft' or 'sent' state."}
  },
  "required": ["id"]
}

{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Lead name or company name to search for. Partial match supported."},
    "stage_id": {"type": "integer", "description": "Pipeline stage ID to filter by. Common stages: New=1, Qualified=2, Proposition=3, Won=4, Lost=5."},
    "limit": {"type": "integer", "description": "Maximum number of results. Default is 10. Use higher for pipeline overview."}
  }
}

{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Lead name or company name (REQUIRED). This is how the lead will be identified."},
    "partner_name": {"type": "string", "description": "Company or contact name for the lead (optional)."},
    "email_from": {"type": "string", "description": "Email address of the contact (optional but recommended)."},
    "phone": {"type": "string", "description": "Phone number of the contact (optional)."},
    "user_id": {"type": "integer", "description": "Salesperson ID to assign the lead to. Find using employee_search if needed."},
    "expected_revenue": {"type": "number", "description": "Estimated deal value or revenue amount (optional)."}
  },
  "required": ["name"]
}

{
  "type": "object",
  "properties": {
    "partner_name": {"type": "string", "description": "Customer or vendor name to filter invoices by. Use exact name as in partner records."},
    "state": {"type": "string", "enum": ["draft", "posted", "paid", "cancel"], "description": "Invoice status. Options: 'draft' (not yet validated), 'posted' (validated, awaiting payment), 'paid' (payment received), 'cancel' (cancelled)."},
    "limit": {"type": "integer", "description": "Maximum number of results. Default is 10. Use higher for accounts receivable/payable reports."}
  }
}

{
  "type": "object",
  "properties": {
    "id": {"type": "integer", "description": "Invoice ID to retrieve (REQUIRED). Find the ID first using invoice_search if you don't know it."}
  },
  "required": ["id"]
}

{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Product name to search for (partial match supported). Use as primary search term."},
    "default_code": {"type": "string", "description": "Product SKU or internal reference code to search by."},
    "limit": {"type": "integer", "description": "Maximum number of results. Default is 10. Use higher for full catalog."}
  }
}

{
  "type": "object",
  "properties": {
    "product_id": {"type": "integer", "description": "Product ID to check stock for. Find ID using product_search first."},
    "location_id": {"type": "integer", "description": "Warehouse/location ID to check (optional). Default shows all locations."},
    "limit": {"type": "integer", "description": "Maximum number of results. Default is 20."}
  }
}

{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Event title or meeting name (REQUIRED). Be descriptive (e.g., 'Customer Call - Acme Corp', 'Team Standup')."},
    "start": {"type": "string", "description": "Start date and time in ISO 8601 format (REQUIRED). Example: '2025-01-15 09:00:00'"},
    "stop": {"type": "string", "description": "End date and time in ISO 8601 format (REQUIRED). Must be after start time. Example: '2025-01-15 10:00:00'"},
    "partner_ids": {"type": "array", "description": "Attendee IDs (optional). List of partner/contact IDs to invite. Find using partner_search first.", "items": {"type": "integer"}}
  },
  "required": ["name", "start", "stop"]
}

{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Ticket subject/title (REQUIRED). Be brief but descriptive (e.g., 'Cannot access login page', 'Invoice discrepancy for INV-001')."},
    "description": {"type": "string", "description": "Detailed description of the issue or request (REQUIRED). Include steps to reproduce if applicable."},
    "partner_id": {"type": "integer", "description": "Customer/contact ID (optional). Find using partner_search first."},
    "priority": {"type": "string", "enum": ["0", "1", "2", "3"], "description": "Priority level. Options: '0' (Low), '1' (Medium), '2' (High), '3' (Urgent). Default is '1'."}
  },
  "required": ["name", "description"]
}

{
  "type": "object",
  "properties": {
    "name": {"type": "string", "description": "Employee name to search for (partial match supported). Use as primary search term."},
    "department_id": {"type": "integer", "description": "Department ID to filter by. Common departments: Sales, Engineering, HR, Finance, Operations."},
    "limit": {"type": "integer", "description": "Maximum number of results. Default is 10. Use higher for full staff directory."}
  }
}
